update_check	a:2:{s:10:"last_check";i:1774506113;s:4:"news";a:3:{i:0;a:5:{s:5:"title";s:19:"Warm up to MyBB 1.9";s:11:"description";s:317:"Yearly wrap-ups, parcels, garlands&#8230; the summer is here, mate. If you found yourself on a chilly night (or hemisphere), read on to warm up as we take a look at another MyBB 1.9 milestone. &#160; Fresh Out the Oven Recent code on the development branch included the topping up of the new theme logic — [&#8230;]";s:4:"link";s:53:"https://blog.mybb.com/2025/12/22/warm-up-to-mybb-1-9/";s:6:"author";s:9:"MyBB Team";s:8:"dateline";i:1766425634;}i:1;a:5:{s:5:"title";s:55:"MyBB 1.8.39 Released — Security & Maintenance Release";s:11:"description";s:409:"MyBB 1.8.39 is now available, and is a security &#38; maintenance release. 2 security vulnerabilities addressed: Medium risk: Upgrade local file inclusion (advisory) &#8212; reported by Cillian Collins Low risk: Unviewable threads title disclosure in search (advisory) &#8212; reported by Huseyn (Khatai) Gadashov (Exploit Azerbaijan) 37 issues resolved Check the Release Notes for more information. [&#8230;]";s:4:"link";s:83:"https://blog.mybb.com/2025/06/02/mybb-1-8-39-released-security-maintenance-release/";s:6:"author";s:9:"MyBB Team";s:8:"dateline";i:1748877505;}i:2;a:5:{s:5:"title";s:26:"Exponential Project Update";s:11:"description";s:0:"";s:4:"link";s:60:"https://blog.mybb.com/2024/07/03/exponential-project-update/";s:6:"author";s:9:"MyBB Team";s:8:"dateline";i:1720032990;}}}
