COPY public.mybb_themestylesheets (sid, name, tid, attachedto, stylesheet, cachefile, lastmodified) FROM stdin;
1	global.css	1		body {\n\tbackground: #fff;\n\tcolor: #333;\n\ttext-align: center;\n\tline-height: 1.4;\n\tmargin: 0;\n\tfont-family: Tahoma, Verdana, Arial, Sans-Serif;\n\tfont-size: 13px;\n\toverflow-y: scroll;\n}\n\na:link {\n\tcolor: #0072BC;\n\ttext-decoration: none;\n}\n\na:visited {\n\tcolor: #0072BC;\n\ttext-decoration: none;\n}\n\na:hover,\na:active {\n\tcolor: #0072BC;\n\ttext-decoration: underline;\n}\n\n#container {\n\tcolor: #333;\n\ttext-align: left;\n\tline-height: 1.4;\n\tmargin: 0;\n\tfont-family: Tahoma, Verdana, Arial, Sans-Serif;\n\tfont-size: 13px;\n\tmin-width: 990px;\n}\n\n.wrapper {\n\twidth: 85%;\n\tmin-width: 970px;\n\tmax-width: 1500px;\n\tmargin: auto auto;\n}\n\n#logo {\n\tbackground: #fff;\n\tpadding: 10px 0;\n\tborder-bottom: 1px solid #263c30;\n}\n\n#content {\n\tbackground: #fff;\n\twidth: auto !important;\n\tpadding: 20px 10px;\n\toverflow: hidden;\n}\n\n#header ul.menu {\n\tmargin: 0;\n\tpadding: 0;\n\tlist-style: none;\n}\n\n#header ul.menu li {\n\tmargin: 0 7px;\n\tdisplay: inline;\n}\n\n#header ul.menu li a {\n\tpadding-left: 20px;\n\tbackground-image: url(images/headerlinks_sprite.png);\n\tbackground-repeat: no-repeat;\n\tdisplay: inline-block;\n\tline-height: 16px;\n}\n\n#logo ul.top_links {\n\tfont-weight: bold;\n\ttext-align: right;\n\tmargin: -10px 5px 0 0;\n}\n\n#logo ul.top_links a.search {\n\tbackground-position: 0 0;\n}\n\n#logo ul.top_links a.memberlist {\n\tbackground-position: 0 -20px;\n}\n\n#logo ul.top_links a.calendar {\n\tbackground-position: 0 -40px;\n}\n\n#logo ul.top_links a.help {\n\tbackground-position: 0 -60px;\n}\n\n#logo ul.top_links a.portal {\n\tbackground-position: 0 -180px;\n}\n\n#panel .upper a.logout {\n\tfont-weight: bold;\n\tbackground: url(images/headerlinks_sprite.png) right -80px no-repeat;\n\tpadding-right: 20px;\n\tmargin-left: 10px;\n}\n\n#panel .upper a.login,\n#panel .upper a.lost_password {\n\tbackground: url(images/headerlinks_sprite.png) 0 -100px no-repeat;\n\tpadding-left: 20px;\n\tmar