-- Name: mybb_users; Type: TABLE; Schema: public; Owner: postgres
--

CREATE TABLE public.mybb_users (
    uid integer NOT NULL,
    username character varying(120) DEFAULT ''::character varying NOT NULL,
    password character varying(120) DEFAULT ''::character varying NOT NULL,
    salt character varying(10) DEFAULT ''::character varying NOT NULL,
    loginkey character varying(50) DEFAULT ''::character varying NOT NULL,
    email character varying(220) DEFAULT ''::character varying NOT NULL,
    postnum integer DEFAULT 0 NOT NULL,
    threadnum integer DEFAULT 0 NOT NULL,
    avatar character varying(200) DEFAULT ''::character varying NOT NULL,
    avatardimensions character varying(10) DEFAULT ''::character varying NOT NULL,
    avatartype character varying(10) DEFAULT '0'::character varying NOT NULL,
    usergroup smallint DEFAULT '0'::smallint NOT NULL,
    additionalgroups character varying(200) DEFAULT ''::character varying NOT NULL,
    displaygroup smallint DEFAULT '0'::smallint NOT NULL,
    usertitle character varying(250) DEFAULT ''::character varying NOT NULL,
    regdate integer DEFAULT 0 NOT NULL,
    lastactive integer DEFAULT 0 NOT NULL,
    lastvisit integer DEFAULT 0 NOT NULL,
    lastpost integer DEFAULT 0 NOT NULL,
    website character varying(200) DEFAULT ''::character varying NOT NULL,
    skype character varying(75) DEFAULT ''::character varying NOT NULL,
    google character varying(75) DEFAULT ''::character varying NOT NULL,
    birthday character varying(15) DEFAULT ''::character varying NOT NULL,
    birthdayprivacy character varying(4) DEFAULT 'all'::character varying NOT NULL,
    signature text DEFAULT ''::text NOT NULL,
    allownotices smallint DEFAULT '0'::smallint NOT NULL,
    hideemail smallint DEFAULT '0'::smallint NOT NULL,
    subscriptionmethod smallint DEFAULT '0'::smallint NOT NULL,
    invisible smallint DEFAULT '0'::smallint NOT NULL,
    receivepms smallint DEFAULT '0'::smallint NOT NULL,
    receivefrombuddy smallint DEFAULT '0'::smallint NOT NULL,
    pmnotice smallint DEFAULT '0'::smallint NOT NULL,
    pmnotify smallint DEFAULT '0'::smallint NOT NULL,
    buddyrequestspm smallint DEFAULT '1'::smallint NOT NULL,
    buddyrequestsauto smallint DEFAULT '0'::smallint NOT NULL,
    threadmode character varying(8) DEFAULT ''::character varying NOT NULL,
    showimages smallint DEFAULT '0'::smallint NOT NULL,
    showvideos smallint DEFAULT '0'::smallint NOT NULL,
    showsigs smallint DEFAULT '0'::smallint NOT NULL,
    showavatars smallint DEFAULT '0'::smallint NOT NULL,
    showquickreply smallint DEFAULT '0'::smallint NOT NULL,
    showredirect smallint DEFAULT '0'::smallint NOT NULL,
    ppp smallint DEFAULT '0'::smallint NOT NULL,
    tpp smallint DEFAULT '0'::smallint NOT NULL,
    daysprune smallint DEFAULT '0'::smallint NOT NULL,
    dateformat character varying(4) DEFAULT ''::character varying NOT NULL,
    timeformat character varying(4) DEFAULT ''::character varying NOT NULL,
    timezone character varying(5) DEFAULT ''::character varying NOT NULL,
    dst smallint DEFAULT '0'::smallint NOT NULL,
    dstcorrection smallint DEFAULT '0'::smallint NOT NULL,
    buddylist text DEFAULT ''::text NOT NULL,
    ignorelist text DEFAULT ''::text NOT NULL,
    style smallint DEFAULT '0'::smallint NOT NULL,
    away smallint DEFAULT '0'::smallint NOT NULL,
    awaydate integer DEFAULT 0 NOT NULL,
    returndate character varying(15) DEFAULT ''::character varying NOT NULL,
    awayreason character varying(200) DEFAULT ''::character varying NOT NULL,
    pmfolders text DEFAULT ''::text NOT NULL,
    notepad text DEFAULT ''::text NOT NULL,
    referrer integer DEFAULT 0 NOT NULL,
    referrals integer DEFAULT 0 NOT NULL,
    reputation integer DEFAULT 0 NOT NULL,
    regip text DEFAULT '\x'::bytea NOT NULL,
    lastip text DEFAULT '\x'::bytea NOT NULL,
    language character varying(50) DEFAULT ''::character varying NOT NULL,
    timeonline integer DEFAULT 0 NOT NULL,
    showcodebuttons smallint DEFAULT '1'::smallint NOT NULL,
    totalpms integer DEFAULT 0 NOT NULL,
    unreadpms integer DEFAULT 0 NOT NULL,
    warningpoints integer DEFAULT 0 NOT NULL,
    moderateposts integer DEFAULT 0 NOT NULL,
    moderationtime integer DEFAULT 0 NOT NULL,
    suspendposting smallint DEFAULT '0'::smallint NOT NULL,
    suspensiontime integer DEFAULT 0 NOT NULL,
    suspendsignature smallint DEFAULT '0'::smallint NOT NULL,
    suspendsigtime integer DEFAULT 0 NOT NULL,
    coppauser smallint DEFAULT '0'::smallint NOT NULL,
    classicpostbit smallint DEFAULT '0'::smallint NOT NULL,
    loginattempts smallint DEFAULT '0'::smallint NOT NULL,
    loginlockoutexpiry integer DEFAULT 0 NOT NULL,
    usernotes text DEFAULT ''::text NOT NULL,
    sourceeditor smallint DEFAULT '0'::smallint NOT NULL,
    newpoints numeric(16,2) DEFAULT 0 NOT NULL
);


